import{_ as e,o as t,c as a}from"./chunks/framework.DXGyWiRo.js";const h=JSON.parse('{"title":"LinkedQL","description":"","frontmatter":{"layout":"home","title":"LinkedQL","hero":{"name":"LinkedQL","text":"Universal Query Engine For the New Chapter","tagline":"LinkedQL moves applications from ad-hoc data stacks and scaffold layers to full SQL power.","actions":[{"theme":"brand","text":"Get Started","link":"/guides/"},{"theme":"alt","text":"What Is LinkedQL","link":"/overview"},{"theme":"alt","text":"Star on GitHub","link":"https://github.com/linked-db/linked-ql"}]},"features":[{"title":"Relationships, Solved","details":"Query data as objects with direct relationship traversal. LinkedQL removes the need for post-processing and object-relational mapping."},{"title":"Realtime, Solved","details":"Drive application state directly with live queries – without touching a subscription server or wiring reactivity. The query is the subscription."},{"title":"Sync, Solved","details":"Sync data between local and remote databases in standard SQL vocabulary. With LinkedQL, the database itself is the sync engine."},{"title":"Runs on Your Database","details":"Run on your own PostgreSQL or MySQL/MariaDB instance. LinkedQL integrates with your database as a query client (db.query())."},{"title":"Runs Locally","details":"Embed LinkedQL as a full SQL engine locally, via FlashQL. FlashQL runs anywhere JavaScript does: server, browser, worker, edge."},{"title":"Runs Universally","details":"Query databases across runtime boundaries through a single protocol. LinkedQL lets clients query data directly, from local to remote."}]},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),i={name:"index.md"};function n(s,r,o,l,d,c){return t(),a("div")}const p=e(i,[["render",n]]);export{h as __pageData,p as default};
